module RefModule (
    input [3:0] A,
    input [3:0] B,
    input CI,
    output [3:0] SUM,
    output COUT_N
);

      wire _n01 = A + B[0] ^ CI[0];
  wire _c01 = A + B[0] & CI[0];
  wire _n02 = A + B[1] ^ CI[1] ^ _c01;
  wire _c02 = (A + B[1] & CI[1]) | (A + B[1] & _c01) | (CI[1] & _c01);
  wire _n03 = A + B[2] ^ CI[2] ^ _c02;
  wire _c03 = (A + B[2] & CI[2]) | (A + B[2] & _c02) | (CI[2] & _c02);
  wire _n04 = A + B[3] ^ CI[3] ^ _c03;
  wire _c04 = (A + B[3] & CI[3]) | (A + B[3] & _c03) | (CI[3] & _c03);
  assign SUM = {_n01, _n02, _n03, _n04};
    assign COUT_N = (A[3] & B[3]) | (A[3] & CI) | (B[3] & CI);

endmodule
